#include<string.h>
#include<ctype.h>
int main(){
int count=0,couta=0;
char s[52];
int x,i,n;
int y;
scanf("%s",&s);
x=strlen(s);
for(i=0;i<x;i++){
if(s[i]=='a'){
couta++;
}
if(s[i]>='b'&& s[i]<='z'){
count++;
}
}

if(couta>count){
    printf("%d",x);

}
else if(count>couta){
    y=count-couta;
    printf("%d",x-y-1);
}
else if(couta==count){
    printf("%d",x-1);
}

return 0;
}

